        const absoluteLink = result.find(link => link.url === 'https://example.com/page1');
        assert(absoluteLink, 'Should extract absolute link');
        assert.equal(absoluteLink.text, 'Page 1', 'Should extract link text');

        done();
    });

    it('should handle relative URLs correctly', function(done) {
        const htmlData = `
            <html>
                <body>
                    <a href="/about">About</a>
                    <a href="contact.html">Contact</a>
                    <a href="../parent">Parent Directory</a>
                </body>
            </html>
        `;
        const sourceUrl = 'https://example.com/subfolder/';

        const result = crawler_url_parser.extract(htmlData, sourceUrl);

        const aboutLink = result.find(link => link.url.includes('/about'));
        assert(aboutLink, 'Should resolve relative URL starting with /');

        done();
    });

    it('should filter out invalid links', function(done) {
        const htmlData = `
            <html>
                <body>
                    <a href="javascript:void(0)">JavaScript Link</a>
                    <a href="mailto:test@example.com">Email Link</a>
                    <a href="ftp://ftp.example.com">FTP Link</a>
                    <a href="">Empty Link</a>
                    <a href="ab">Too Short</a>
                    <a href="https://valid.com">Valid Link</a>
                </body>
            </html>
        `;
        const sourceUrl = 'https://example.com';

        const result = crawler_url_parser.extract(htmlData, sourceUrl);

        // Should only contain the valid link
